import React, { useState } from 'react';
import { Helmet } from 'react-helmet-async';
import { useAuth } from '../contexts/AuthContext';
import { useNavigate } from 'react-router-dom';

const DonationPage = () => {
  const { user } = useAuth();
  const navigate = useNavigate();
  const [amount, setAmount] = useState('');
  const [paymentMethod, setPaymentMethod] = useState('upi');
  const [isAnonymous, setIsAnonymous] = useState(false);

  const presetAmounts = [500, 1000, 2500, 5000, 10000];

  const handleDonate = async () => {
    if (!amount || amount < 1) {
      alert('Please enter a valid donation amount');
      return;
    }

    // TODO: Implement donation logic
    alert(`Donation of ₹${amount} via ${paymentMethod} will be processed`);
  };

  return (
    <>
      <Helmet>
        <title>Make a Donation - Impact Foundation</title>
        <meta name="description" content="Make a secure donation to Impact Foundation and support our mission to create lasting change." />
      </Helmet>
      
      <div className="min-h-screen bg-gray-50 py-12">
        <div className="container-custom">
          <div className="max-w-2xl mx-auto">
            <div className="text-center mb-8">
              <h1 className="text-3xl md:text-4xl font-bold mb-4 gradient-text">
                Make a Donation
              </h1>
              <p className="text-lg text-gray-600">
                Your generous contribution helps us create lasting change in communities.
              </p>
            </div>

            <div className="bg-white rounded-xl shadow-medium p-8">
              {/* User Info */}
              <div className="mb-6 p-4 bg-gray-50 rounded-lg">
                <h3 className="font-semibold text-gray-900 mb-2">Donor Information</h3>
                <p className="text-gray-600">{user?.name}</p>
                <p className="text-gray-600">{user?.email}</p>
                <p className="text-gray-600">{user?.phone}</p>
                {user?.kycStatus !== 'verified' && (
                  <div className="mt-2 p-2 bg-yellow-100 text-yellow-800 rounded text-sm">
                    KYC verification required for donations above ₹10,000
                  </div>
                )}
              </div>

              {/* Amount Selection */}
              <div className="mb-6">
                <label className="block text-sm font-medium text-gray-700 mb-3">
                  Select Amount (₹)
                </label>
                <div className="grid grid-cols-3 gap-3 mb-4">
                  {presetAmounts.map((preset) => (
                    <button
                      key={preset}
                      type="button"
                      onClick={() => setAmount(preset)}
                      className={`py-3 px-4 rounded-lg border-2 font-medium transition-colors ${
                        amount === preset
                          ? 'border-primary-500 bg-primary-50 text-primary-700'
                          : 'border-gray-300 hover:border-gray-400'
                      }`}
                    >
                      ₹{preset}
                    </button>
                  ))}
                </div>
                <input
                  type="number"
                  value={amount}
                  onChange={(e) => setAmount(e.target.value)}
                  placeholder="Enter custom amount"
                  className="w-full px-4 py-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-primary-500 focus:border-transparent"
                  min="1"
                />
              </div>

              {/* Payment Method */}
              <div className="mb-6">
                <label className="block text-sm font-medium text-gray-700 mb-3">
                  Payment Method
                </label>
                <div className="space-y-3">
                  {[
                    { value: 'upi', label: 'UPI (Google Pay/PhonePe)', icon: '📱' },
                    { value: 'card', label: 'Credit/Debit Card', icon: '💳' },
                    { value: 'netbanking', label: 'Net Banking', icon: '🏦' },
                    { value: 'wallet', label: 'Wallet (Paytm/PhonePe)', icon: '👛' },
                  ].map((method) => (
                    <label
                      key={method.value}
                      className={`flex items-center p-4 border-2 rounded-lg cursor-pointer transition-colors ${
                        paymentMethod === method.value
                          ? 'border-primary-500 bg-primary-50'
                          : 'border-gray-300 hover:border-gray-400'
                      }`}
                    >
                      <input
                        type="radio"
                        value={method.value}
                        checked={paymentMethod === method.value}
                        onChange={(e) => setPaymentMethod(e.target.value)}
                        className="mr-3"
                      />
                      <span className="text-2xl mr-3">{method.icon}</span>
                      <span className="font-medium">{method.label}</span>
                    </label>
                  ))}
                </div>
              </div>

              {/* Anonymous Donation */}
              <div className="mb-6">
                <label className="flex items-center">
                  <input
                    type="checkbox"
                    checked={isAnonymous}
                    onChange={(e) => setIsAnonymous(e.target.checked)}
                    className="mr-2"
                  />
                  <span className="text-sm text-gray-700">
                    Make this donation anonymous
                  </span>
                </label>
              </div>

              {/* Security Info */}
              <div className="mb-6 p-4 bg-blue-50 rounded-lg">
                <h4 className="font-semibold text-blue-900 mb-2">🔒 Secure Payment</h4>
                <ul className="text-sm text-blue-800 space-y-1">
                  <li>• 256-bit SSL encryption</li>
                  <li>• PCI DSS compliant</li>
                  <li>• 80G tax benefit available</li>
                  <li>• 7-day verification period</li>
                </ul>
              </div>

              {/* Donate Button */}
              <button
                onClick={handleDonate}
                disabled={!amount || amount < 1}
                className="w-full btn-primary py-4 text-lg font-semibold disabled:opacity-50 disabled:cursor-not-allowed"
              >
                Donate ₹{amount || '0'}
              </button>

              {/* Terms */}
              <p className="mt-4 text-xs text-gray-500 text-center">
                By donating, you agree to our Terms of Service and Privacy Policy.
                All donations are final and non-refundable after 7-day verification period.
              </p>
            </div>
          </div>
        </div>
      </div>
    </>
  );
};

export default DonationPage;
